var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"왔어요, 왔어. 호출을 듣고 크레데레가 찾아왔습니다.","JPN":"来ました、来ました。呼び出しを聞いて、クレデレがやって来ました。","ENG":"Lo and behold. Credere is here from your call.","TWN":"來啦來啦。一聽到老闆找，克蕾妲莉就跑來囉。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"하고 싶은 말이 있으시겠지만… 쉿. 크레데레는 이미 사장이 할 말을 알고 있습니다.","JPN":"言いたいことがあると思いますが……しっ。クレデレはすでに社長が言わんとしていることを知っています。","ENG":"You probably have something to say, but... Shh. Credere already knows.","TWN":"老闆應該有話要說吧…噓，克蕾妲莉知道老闆想說什麼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"안타깝지만 죄 많은 크레데레가 또 한 명의 남성을 유혹한 모양이로군요.","JPN":"残念ながら罪深いクレデレがまた一人の男性を誘惑したみたいですね。","ENG":"It seems that Credere has seduced yet another innocent man.","TWN":"紅顏禍水的克蕾妲莉似乎又吸引到一名男性。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"유감입니다, 사장. 크레데레는 아직 법적으로 결혼할 수 있는 나이가 아니거든요.","JPN":"残念です、社長。クレデレはまだ法的に結婚できる年齢ではないんですよ。","ENG":"Sorry to tell you, but Credere isn't old enough to get legally married yet.","TWN":"但很抱歉，老闆。克蕾妲莉還不達到適婚年齡。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"저희 아빠에게 혼나기 싫다면 얌전히 시기를 기다리시길.","JPN":"うちのパパに怒られたくなければ、大人しく時期を待ってください。","ENG":"Please wait patiently if you don't want to get beat up by my dad.","TWN":"要是不想被克蕾妲莉的爸爸罵，就乖乖等克蕾妲莉長大吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"음… 종신계약? 프러포즈가 아니라고요?","JPN":"うーん……終身契約？　プロポーズじゃないんですか？","ENG":"Um... A lifetime contract? You're not proposing?","TWN":"蛤…是終身契約？不是求婚喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"이런. 차일 걸 대비해 핑계로 쓸 종이까지 준비하다니. 참으로 주도면밀하군요.","JPN":"あら。振られることに備えて言い訳に使う紙まで用意するなんて。本当に用意周到ですね。","ENG":"Oh, dear. You even prepared a piece of paper to use as an excuse in case you got rejected. How meticulous.","TWN":"哎呀，竟然連被拒絕之後的藉口都想好啦？想得很周到呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"좋습니다. 착한 크레데레가 이번에는 장단을 맞춰드리죠.","JPN":"いいですよ。今回はいい子のクレデレが合せてあげます。","ENG":"Very well. Credere is kind enough to play along.","TWN":"好吧，善良的克蕾妲莉這次就配合老闆吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"어디……","JPN":"さて……","ENG":"Let's see...","TWN":"克蕾妲莉看看喔……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"여기 오타가 있습니다, 사장. 크레데레가 갑이고 사장이 을이어야 하는데 여긴 반대로 적혀져 있어요.","JPN":"社長、ここに誤字があります。クレデレが甲で社長が乙でなければならないのに、ここは反対に書かれています。","ENG":"There is a typo here. Credere should be the boss and you should be the employee, but it says the opposite.","TWN":"這裡有個錯誤，老闆。克蕾妲莉應該是甲方，老闆才是乙方，這裡寫反咧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"네? 크레데레가 을이 맞다고요?","JPN":"え？　クレデレが乙で合ってるんですか？","ENG":"What? Credere \\"is\\" the employee?","TWN":"什麼？克蕾妲莉是乙方沒錯嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"협상 결렬입니다. 지금 당장 저 문을 열고 크레데레를 풀어주세요.","JPN":"交渉決裂です。今すぐあのドアを開けてクレデレを解放してください。","ENG":"Negotiations end here. Open that door right now and let Credere out.","TWN":"談判破裂，現在立刻打開那扇門，放克蕾妲莉出去。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레는 누구 밑에서 일하고 그러는…","JPN":"クレデレは誰かの下で働いたりするのは……","ENG":"Credere doesn't work under anyone... ","TWN":"克蕾妲莉是不會受雇於誰的…等等，老闆怎麼可以擅自進行對話。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"아니, 왜 사장 멋대로 이야기를 진행하는 건가요.","JPN":"いいえ、なぜ社長が勝手に話を勧めるんですか。","ENG":"Wait, stop. Why are you proceeding with things on your own?","TWN":"把手拿開，不要亂按，喂！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"터치 멈추라고, 어이-.","JPN":"タッチしないで、もう。","ENG":"Hands off the paper. Arr."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};